exp#include &lt;stdio.h&gt;#include &lt;stdint.h&gt;#include &lt;string.h&gt;#include &lt;openssl/md5.h&gt;#define LEFTROTATE(x, c) (((x) &lt;&lt; (c)) | ((x) &gt;&gt; (32 - (c))))unsigned int seed ;// unsigned int first = 1751990400;// unsigned int end =  1752052051;// v1 = (((dword_7FF75004B040 &lt;&lt; 13) ^ (unsigned int)dword_7FF75004B040) &gt;&gt; 17) ^ (dword_7FF75004B040 &lt;&lt; 13) ^ dword_7FF75004B040;// dword_7FF75004B040 = (32 * v1) ^ v1;// return dword_7FF75004B040 &amp; 0x7FFFFFFF;int random()&#123;    unsigned int x = (seed &lt;&lt; 13) ^seed;    unsigned int y = (x &gt;&gt; 17) ^ x;    seed =(y * 32)^y;    return seed &amp; 0x7FFFFFFF;&#125;void md5hexToString(unsigned char *md, char *result) &#123;  for (size_t i = 0; i &lt; 16; i++) &#123;      sprintf(result + i * 2, &quot;%02x&quot;, md[i]);  &#125;  result[32] = &#x27;\0&#x27;;&#125;int main()&#123;    for (int i = 1751990400; i &lt; 1752052051; i++)  &#123;    char query[256];    unsigned char digest[16];    char flag[33] = &#123;0&#125;;     int v58 = 0;    int v57 = 0;    int v56 = 0;    int v55 = 0;    seed = i;            for (int k = 0; k &lt; (int)random(); ++k )    &#123;        v58 = random();        v57 = random();        v56 = random();        v55 = random();    &#125;    int v52 = random();        snprintf(query, sizeof(query),  &quot;salt=tlkyeueq7fej8vtzitt26yl24kswrgm5&amp;t=%u&amp;r=%d&amp;a=%d&amp;b=%d&amp;x=%d&amp;y=%d&quot;,  i, v52, v58, v57, v56, v55);  printf(&quot;%s\n&quot;, query);  MD5((unsigned char *)query, strlen(query), digest);  md5hexToString(digest, flag);  printf(&quot;%s\n&quot;, flag);  if (!strcmp(flag, &quot;8a2fc1e9e2830c37f8a7f51572a640aa&quot;)) &#123;      printf(&quot; Found at time: %d\n&quot;, seed);      return 0;  &#125;&#125;return 0;&#125;// salt=tlkyeueq7fej8vtzitt26yl24kswrgm5&amp;t=1751994277&amp;r=101356418&amp;a=1388848462&amp;b=441975230&amp;x=1469980073&amp;y=290308156// 8a2fc1e9e2830c37f8a7f51572a640aa//  Found at time: 101356418// L3HCTF&#123;5cbbe37231ca99bd009f7eb67f49a98caae2bb0f&#125;

