反编译出来的内容 cipher=[0x30,0x37,0x39,0x32,0x35,0x37,0x35,0x32,0x34,0x32,0x30,0x37,0x65,0x34,0x35,0x32,0x34,0x32,0x34,0x32,0x30,0x37,0x35,0x37,0x37,0x37,0x32,0x36,0x35,0x37,0x36,0x37,0x37,0x37,0x35,0x36,0x62,0x37,0x61,0x36,0x32,0x35,0x38,0x34,0x32,0x34,0x63,0x36,0x32,0x32,0x34,0x32,0x32,0x36]def str_to_hex_bytes(s: str) -&gt; bytes: return s.encode(&quot;utf-8&quot;)def enc(data: bytes, key: int) -&gt; bytes: return bytes([b ^ key for b in data])def en3(b: int) -&gt; int: # 循环左移4位，相当于高低半字节交换 return ((b &lt;&lt; 4) &amp; 0xF0) | ((b &gt;&gt; 4) &amp; 0x0F)def en33(data: bytes, n: int) -&gt; bytes: &quot;&quot;&quot;整体 bitstream 循环左移 n 位&quot;&quot;&quot; bit_len = len(data) * 8 n = n % bit_len # 转成整数 val = int.from_bytes(data, &quot;big&quot;) val = ((val &lt;&lt; n) | (val &gt;&gt; (bit_len - n))) &amp; ((1 &lt;&lt; bit_len) - 1) return val.to_bytes(len(data), &quot;big&quot;)if __name__ == &quot;__main__&quot;: flag =&quot;&quot; data = str_to_hex_bytes(flag) # 2. xor 0x11 data = enc(data, 0x11) # 3. 循环左移4位（对每字节） data = bytes([en3(b) for b in data]) # 4. reverse data = data[::-1] # 5. 整体循环左移32位 data = en33(data, 32) # 6. tohex if data.hex() == cipher: print(&quot;Correct! &quot;) else: print(&quot;Wrong！！！！！！！！&quot;)
每一步反着改回去即可： exp: cipher = [48, 55, 57, 50, 53, 55, 53, 50, 52, 50, 48, 55, 101, 52, 53, 50, 52, 50, 52, 50, 48, 55, 53, 55, 55, 55, 50, 54, 53, 55, 54, 55, 55, 55, 53, 54, 98, 55, 97, 54, 50, 53, 56, 52, 50, 52, 99, 54, 50, 50, 52, 50, 50, 54]def enc(data: bytes, key: int) -&gt; bytes: return bytes([b ^ key for b in data])def en3(b: int) -&gt; int: return b &lt;&lt; 4 &amp; 240 | b &gt;&gt; 4 &amp; 15def en33(data: bytes, n: int) -&gt; bytes: bit_len = len(data) * 8 n = n % bit_len val = int.from_bytes(data, &#x27;big&#x27;) val = (val &gt;&gt; n | val &lt;&lt; bit_len - n) &amp; (1 &lt;&lt; bit_len) - 1 return val.to_bytes(len(data), &#x27;big&#x27;)if __name__ == &#x27;__main__&#x27;: data = bytes.fromhex(bytes(cipher).decode()) data = en33(data, 32) data = data[::-1] data = bytes([en3(b) for b in data]) data = enc(data, 17) print(data)# SYC&#123;jtfgdsfda554_a54d8as53&#125;
only_flowersource code 第一周似乎有挺多选手哭这道的？但是其实只有一种花 花指令实则就是垃圾代码，它不会影响程序运行但是会影响IDA反编译 可以了解一下IDA递归下降反编译&amp;花指令原理 因为不影响执行，所以花指令动调一下就直接可以跳过，把跳过的字节码nop调就可以。我们讲静态： 实现原理： __asm__ __volatile__ ( &quot;.byte 0xEB,0xFF,0xC0,0x48;&quot;);
0xEB JMP rel8（短跳转指令）
0xFF 作为 JMP 的 跳转偏移（-1），也会被当作下一条指令的 opcode 导致错位
0xC0 根据上下文会被解析成各种非法或奇怪指令
0x48 REX.W 前缀（x86_64），单独出现会让反汇编器误判接下来的结构
IDA里反编译的效果： .text:0040161F loc_40161F: ; CODE XREF: _main:loc_40161F↑j.text:0040161F EB FF jmp short near ptr loc_40161F+1.text:0040161F _main endp.text:0040161F.text:0040161F ; ---------------------------------------------------------------------------.text:00401621 C0 48 A1 db 0C0h, 48h, 0A1h 首先你需要打开字节码：IDA-Options-General-Numbers of Opcode这里改成5或者10 EB FF就是字节码 jmp short near ptr loc_40161F+1的意思是跳到loc_40161F往后偏移 +1 字节的地址，所以是跳过EB执行FF，也就是跳过JMP指令，首先在0x040161F的位置按U取消定义，把db 0EBh nop掉（不懂nop去搜，可以下一个keypatch）。 下面的也这么去就好了。 去完花就可以看到清晰的逻辑写exp了 # decrypt_onlyflower.pyCIPHER = [ 0x0A,0x84,0xC2,0x84,0x51,0x48,0x5F,0xF2,0x9E,0x8D,0xD0,0x84,0x75,0x67,0x73,0x8F, 0xCA,0x57,0xD7,0xE6,0x14,0x6E,0x77,0xE2,0x29,0xFE,0xDF,0xCC]KEY = b&quot;GEEK2025&quot;def ror8(v, n): n &amp;= 7 return ((v &gt;&gt; n) | ((v &lt;&lt; (8 - n)) &amp; 0xFF)) &amp; 0xFFdef decrypt(cipher, key): klen = len(key) out = bytearray(len(cipher)) for i, y in enumerate(cipher): k = key[i % klen] r = (y - (i &amp; 0xFF)) &amp; 0xFF x = ror8(r, k &amp; 7) b = x ^ k out[i] = b return bytes(out)if __name__ == &quot;__main__&quot;: flag = decrypt(CIPHER, KEY) print(flag.decode(&#x27;utf-8&#x27;))# SYC&#123;asdjjasdhjk12wk12ijkejk&#125;
ezRu3tsource code: https://github.com/Samsara-lo/Geek2025/blob/main/ezRu3t/main.rs shift+F12找到类似Base85和Base64码表的字符串，本意其实不是rust代码审计要求全学一遍，因为校内的进度Base家族不会的话要挨骂了。 密文为&lt;AA;XAM?,_@;T[r@7E779h8;s&gt;’&#96;pt&#x3D;&gt;3c6ASuHFASOtP&lt;Gkf_A4&amp;gPAl1]S 直接base85+base64解密 SYC{Ohjhhh_y0u_g3t_Ezzzzz3_Ru3t!@} ezSMCsource code: https://github.com/Samsara-lo/Geek2025/tree/main/ezSMC ida 打开审计代码，联系题目很容易发现.miao段代码是被SMC加密处理过的 两种解法：1.动调过掉SMC自解密；2.写ida python代码解密 第二种解法可以看这个师傅的，写的很详细：https://fairy-10124.github.io/2025/11/28/Geek%202025%EF%BC%88reverse%E6%96%B9%E5%90%91%EF%BC%89/ 程序主函数： int __fastcall main(int argc, const char **argv, const char **envp)&#123; _main(*(_QWORD *)&amp;argc, argv, envp); Str2 = &quot;tHMoSoMX71sm62ARQ8aHF6i88nhkH9Ac2J7CrkQsQgXpiy6efoC8YVkzZu1tMyFxCLbbqvgXZHxtwK5TACVhPi1EE5mK6JG56wPNR4d2GmkELGfJHgtcAEH7&quot;; printf(&quot;Plz input your flag miao: &quot;); Stream = __acrt_iob_func(0); fgets(Buffer, 1024, Stream); Buffer[strcspn(Buffer, &quot;\r\n&quot;)] = 0; hex = (char *)ascii_to_hexbytes(Buffer, &amp;outlen); data = hexstr_to_bytes(hex, &amp;len); key = 17; init(&amp;ctx, &amp;key, 1); encode(&amp;ctx, data, len); Str = bytes_to_hexstr(data, len); miao_encrypt(); len_1 = strlen(Str); data_1 = (uint8_t *)encodee((const uint8_t *)Str, len_1); if ( data_1 ) &#123; len_2 = strlen((const char *)data_1); Str1 = enc0de(data_1, len_2); if ( !strcmp(Str1, Str2) ) puts(&quot;Correct!&quot;); else puts(&quot;Wrong!&quot;); free(hex); free(data); free(Str); free(data_1); free(Str1); return 0; &#125; else &#123; puts(&quot;encodee returned NULL&quot;); return 0; &#125;&#125;
被SMC的函数是一个base64，加密顺序为密钥为单字节0x11的RC4→转hex→base64→使用自定义表的base58，直接解密即可SYC{OHhhhhhhh_y0u_Kn0m_SMCCCC@!} Week2Mission Ghost SignalRE部分有两个思路：
程序给了解密函数，直接patch 同构AES，发现魔改自实现的S盒
程序主函数： int __cdecl main(int argc, const char **argv, const char **envp)&#123; _BYTE v4[32]; // [esp+1Ch] [ebp-20Ch] BYREF char v5[192]; // [esp+3Ch] [ebp-1ECh] BYREF char Buffer[256]; // [esp+FCh] [ebp-12Ch] BYREF _BYTE v7[16]; // [esp+1FCh] [ebp-2Ch] BYREF int n7; // [esp+20Ch] [ebp-1Ch] int j; // [esp+210h] [ebp-18h] char v10; // [esp+217h] [ebp-11h] int i; // [esp+218h] [ebp-10h] size_t n25_1; // [esp+21Ch] [ebp-Ch] sub_403500(); SetConsoleOutputCP(0xFDE9u); SetConsoleCP(0xFDE9u); qmemcpy(v7, &quot;1145141145144332&quot;, sizeof(v7)); puts(&quot;密码验证系统&quot;); printf(&quot;请输入压缩包密码: &quot;); if ( fgets(Buffer, 256, (FILE *)iob[0]._ptr) ) &#123; n25_1 = strlen(Buffer); if ( n25_1 &amp;&amp; Buffer[n25_1 - 1] == 10 ) Buffer[--n25_1] = 0; if ( n25_1 == 25 ) &#123; sub_401C08(v5, p_Syclover2025Geek, v7); // &quot;Syclover2025Geek&quot; memcpy(v4, Buffer, 0x19u); n7 = 7; for ( i = 25; i &lt;= 31; ++i ) v4[i] = n7; AES_CBC_Modified(v5, v4, 0x20u); v10 = 1; for ( j = 0; j &lt;= 31; ++j ) &#123; if ( byte_406020[j] != v4[j] ) &#123; v10 = 0; break; &#125; &#125; if ( v10 ) puts(&quot;恭喜！这是正确的压缩包密码。&quot;); else puts(&quot;特工，你失败了！密码不正确。&quot;); return 0; &#125; else &#123; puts(&quot;特工，你失败了！密码长度不正确。&quot;); return 1; &#125; &#125; else &#123; puts(&quot;输入错误！&quot;); return 1; &#125;&#125;
其中AES是一个自实现的AES，但程序中给出了解密函数，patch加密为解密即可 .text:00402F59 call AES_CBC_Modified ; 0x402B57↓.text:00402F59 call AES_CBC_Modified_Dec ; 0x402BE8
密码为We_ve_Trapped_in_The_Sink，解压后得到一个sstv，读取得到一张含有二维码的图片，扫描后得到一个下载链接https://wwnr.lanzoum.com/iIjAG39n7mlg，下载后是一个含摩斯电码的音频，识别得到55316C44657A646F4D5456664D564E664E463835636A52755246396A4D4534316344467951474E5A4C6E303D，转hex得到U1lDezdoMTVfMVNfNF85cjRuRF9jME41cDFyQGNZLn0=，解base64得到flag SYC{7h15_1S_4_9r4nD_c0N5p1r@cY.} Week4国产の光其实没什么难度不是week4的题，只要配好鸿蒙反编译环境就行。密文yaApcJ5GoyGwhARDXZLQUdntqPpmVu2GuTChnsLoj5d8ABinwGSsgpGaiPWYbHTTbbzSXxLXwoLgjR1YgquyEnK，自动识别base58，外层密钥welcometosyc2025，iv为helloimsamsaramiao，内层AESCBC，直接解密即可得到flag SYC{HarmonyOS_1s_right?right!} obfuscat3source code：https://github.com/Samsara-lo/Geek2025/blob/main/obfuscat3/obfuscat3.cpp忘记把256处理一下了成简单题了，我的小巧思没了TT可以去学习一下ollvm，这题的主要考点是指令替换+瞪眼法，被瞪的太容易了，很容易发现是一个把最后异或魔改成+的RC4 函数里又调用了init_encode和exchange_encode 具体审核分析代码看起来是有个魔改后又拆分加了混淆的RC4，进行了自定义的S盒流密码变体，其中init_encode函数实现了KSA的功能，exchange_encode函数实现了swap的功能，而obf_encode应该是实现了PRGA的功能，RC4算法的魔改点是把最后char ^ S[(S[i] + S[j]) % 256]​中的异或运算改成了 + ，所以解密的时候只要改成 - 就行了 具体的GAMBA表达式可以看源码，是源代码混淆的基础上套了两层标准ollvm的指令替换 然后就可以写解密代码了 cipher = [ 0xB4, 0xCD, 0x69, 0x54, 0xBD, 0x67, 0x20, 0x9D, 0xF2, 0xC3, 0x24, 0x14, 0xC2, 0x1B, 0xE9, 0x6A, 0x44, 0x14, 0x4E, 0x39, 0xC5, 0xC8, 0x5B, 0x11, 0x75, 0xAD, 0xDE, 0xBB, 0xFE, 0xE4, 0x6E, 0x65, 0x06, 0x9A, 0x91, 0xFE, 0xA0, 0x68, 0xA4, 0x86, 0x17, 0x6C, 0x0A, 0xCF, 0x1E, 0x67, 0xE3, 0x0D, 0x60, 0x47, 0x13, 0x6B, 0xD1, 0x36, 0xF2, 0x77, 0x58, 0x76, 0x1E, 0x98, 0xF5, 0x7F, 0x0A, 0x92, 0xB7, 0x0A, 0xEA, 0xAE, 0x46, 0x7E, 0x6A, 0x18, 0x4A, 0x59, 0x4E, 0x71, 0xB2, 0xE1, 0x41, 0x7A, 0x0B, 0x31, 0xBA, 0xC6, 0xAA, 0xCF, 0xCE, 0x09, 0xBF, 0x2E, 0xF8, 0x4D, 0x75, 0xEF, 0x14, 0xED, 0x5F, 0x66, 0x44, 0x6F, 0xDE, 0xE2, 0x7C, 0x10, 0x8C, 0xB7, 0x4E, 0x6B, 0xB2, 0xD4, 0xF6, 0x91, 0xD7, 0x84, 0x86, 0x1F, 0xF8, 0x65, 0x94, 0x0B, 0x14, 0x28, 0xFB, 0xDD, 0x47, 0xF4, 0xC1, 0x17, 0x42, 0x3F, 0x1E, 0x38, 0x07, 0xBB, 0x37, 0x33, 0x12, 0x0C, 0x16, 0x68, 0xE0, 0x23, 0x12, 0x75, 0x72, 0xD9, 0x71, 0x7A, 0x88, 0xD0, 0x46, 0x28, 0x88, 0xAD, 0x1E, 0x98, 0x8F, 0x92, 0x7E, 0x0E, 0x69, 0x29, 0x37, 0xB1, 0xFF, 0xC5, 0xAF, 0x6F, 0x41, 0x37, 0x65, 0x0E, 0xD2, 0x62, 0x11, 0x8F, 0xA6, 0x3E, 0x95, 0xF5, 0x80, 0x9A, 0xDC]key = b&quot;Samsara&quot;def rc4_keystream(length, key_bytes): S = list(range(256)) j = 0 # KSA for i in range(256): j = (j + S[i] + key_bytes[i % len(key_bytes)]) &amp; 0xFF S[i], S[j] = S[j], S[i] # PRGA i = 0 j = 0 out = [] for _ in range(length): i = (i + 1) &amp; 0xFF j = (j + S[i]) &amp; 0xFF S[i], S[j] = S[j], S[i] K = S[(S[i] + S[j]) &amp; 0xFF] out.append(K) return outks = rc4_keystream(len(cipher), list(key))plain = bytes((c - ks[i]) &amp; 0xFF for i, c in enumerate(cipher))print(plain.decode(&#x27;ascii&#x27;))#SYC&#123;Alright_I_sti1l_h0pe_th3t_you_solved_the_chall3nge_by_deobfuscating_them_Geek_is_just_the_first_step_of_your_CTF_journey_Im_glad_I_could_be_part_of_your_growth_Good_luck_for_y0u!&#125;
