用d810和hrtng反混淆加密函数： unsigned __int8 *__fastcall real_en( unsigned __int8 *inp, unsigned __int8 *key, unsigned __int8 *sbox1, const unsigned __int8 *sbox2)&#123; _inp = inp; _key = key; _sbox1 = sbox1; _sbox2 = sbox2; en1(inp, key, 32); for ( i = 0; i &lt; 32; ++i ) *((_BYTE *)_inp + i) = _sbox1[*((unsigned __int8 *)_inp + i)]; for ( j = 0; j &lt; 32; ++j ) *((_BYTE *)_inp_1 + j) = *((_BYTE *)_inp + (unsigned __int8)perm[j]); __inp = _inp; *(_QWORD *)_inp = _inp_1[0]; __inp[1] = _inp_1[1]; __inp[2] = _inp_1[2]; __inp[3] = _inp_1[3]; ___inp[7] = *_inp; ___inp[6] = _inp[1]; ___inp[5] = _inp[2]; ___inp[4] = _inp[3]; ___inp[3] = _inp[4]; ___inp[2] = _inp[5]; ___inp[1] = _inp[6]; ___inp[0] = _inp[7]; for ( n4 = 0; n4 &lt; 4; ++n4 ) &#123; v11 = *(_DWORD *)&amp;_key[4 * (n4 % 4)]; v7 = ___inp[7]; ___inp[7] = ___inp[6]; ___inp[6] = F(___inp[6], v11, _sbox1) ^ v7; v5 = F(___inp[4], v11, _sbox1); v10 = ___inp[5] ^ v5; ___inp[5] = ___inp[4]; ___inp[4] = v10; v9 = ___inp[3] ^ F(___inp[2], v11, _sbox1); ___inp[3] = ___inp[2]; ___inp[2] = v9; v8 = F(___inp[0], v11, _sbox1) ^ ___inp[1]; ___inp[1] = ___inp[0]; ___inp[0] = v8; &#125; *_inp = ___inp[7]; _inp[1] = ___inp[6]; _inp[2] = ___inp[5]; _inp[3] = ___inp[4]; _inp[4] = ___inp[3]; _inp[5] = ___inp[2]; _inp[6] = ___inp[1]; p_s1a_2 = (unsigned __int8 *)_inp; _inp[7] = ___inp[0]; return p_s1a_2;&#125;
查看en1： __int64 __fastcall en1(unsigned __int8 *inp, const unsigned __int8 *key, int n32)&#123; for ( n32_1 = 0; ; ++n32_1 ) &#123; n32_2 = (unsigned int)n32_1; if ( n32_1 &gt;= n32 ) break; inp[n32_1] = ~((key[n32_1 % 16] | ~inp[n32_1]) &amp; ~(key[n32_1 % 16] &amp; ~inp[n32_1])); &#125; return n32_2;&#125;
是一个循环异或，之后是S盒1替换、顺序替换、倒排、4轮函数、再次倒排，同构： for i in range(32): inp[i] ^= key[i%16]for i in range(32): inp[i] = sbox1[inp[i]]mid = bytearray(32)for i in range(32): mid[i] = inp[perm[i]]dmid = b2nle(mid, 4)dmid = dmid[::-1]for i in range(4): for j in range(0, 8, 2): dmid[j], dmid[j+1] = dmid[j+1] ^ F(dmid[j], dkey[i], sbox1), dmid[j]dmid = dmid[::-1]res = n2ble(dmid, 4)
对于轮函数F： __int64 __fastcall F(int inp, unsigned int dkey, const unsigned __int8 *sbox)&#123; v8 = sbox[((inp ^ dkey) &gt;&gt; 0x00) &amp; 0xFF]; v7 = sbox[((inp ^ dkey) &gt;&gt; 0x08) &amp; 0xFF]; v6 = sbox[((inp ^ dkey) &gt;&gt; 0x10) &amp; 0xFF]; v5 = sbox[((inp ^ dkey) &gt;&gt; 0x18) &amp; 0xFF]; return not_en((v5 &lt;&lt; 0x18) | (v6 &lt;&lt; 0x10) | (v7 &lt;&lt; 0x08) | (v8 &lt;&lt; 0x00), 5);&#125;__int64 __fastcall not_en(unsigned int a1, char n5)&#123; v2 = a1 &lt;&lt; n5; v3 = a1 &gt;&gt; (32 - n5); return v2 | v3;&#125;
是一个异或密钥后S盒替换再循环左移，同构： def b2nle(b, n): return [int.from_bytes(b[i:i+n], byteorder=&#x27;little&#x27;, signed=False) for i in range(0, len(b), n)]def n2ble(na, n): b = bytearray() for a in na: b.extend(a.to_bytes(n, byteorder=&#x27;little&#x27;)) return bkey = bytearray.fromhex(&quot;102030405566778890ABBCCDDEEF0123&quot;)dkey = b2nle(key, 4)perm = bytearray.fromhex(&quot;1F000102030405060708090A0B0C0D0E0F101112131415161718191A1B1C1D1E&quot;)sbox = bytearray(256)inv_sbox = bytearray(256)enc = bytearray.fromhex(&quot;CA5A96FF084972393618138A14C00C78F87C49C7BEE891ED7FB002AD7774D434&quot;)inp = bytearray(b&quot;12345678901234567890123456789012&quot;)def rol(b, shift): shift &amp;= 31 return ((b &lt;&lt; shift) | (b &gt;&gt; (32-shift))) &amp; 0xFFFFFFFFdef gen(sbox, inv_sbox, key): for i in range(256): sbox[i] = i t = 0 for j in range(256): t = (t + key[j % 16] + sbox[j]) &amp; 0xFF sbox[j], sbox[t] = sbox[t], sbox[j] for k in range(256): inv_sbox[sbox[k]] = kdef F(dm, dk, sbox): dm ^= dk bm = n2ble([dm], 4) for i in range(4): bm[i] = sbox[bm[i]] dm = b2nle(bm, 4)[0] return rol(dm, 5)gen(sbox, inv_sbox, key)for i in range(32): inp[i] ^= key[i%16]for i in range(32): inp[i] = sbox[inp[i]]inp = inp[-1:] + inp[:-1]dinp = b2nle(inp, 4)[::-1]for i in range(4): for j in range(6, -2, -2): dinp[j], dinp[j+1] = dinp[j+1] ^ F(dinp[j], dkey[i], sbox), dinp[j]dinp = dinp[::-1]res = n2ble(dinp, 4)print(res.hex())denc = b2nle(enc, 4)denc = denc[::-1]for i in range(3, -1, -1): for j in range(0, 8, 2): denc[j], denc[j+1] = denc[j+1], denc[j] ^ F(denc[j+1], dkey[i], sbox)denc = denc[::-1]benc = n2ble(denc, 4)rec = benc[1:] + benc[:1]for i in range(32): rec[i] = inv_sbox[rec[i]]for i in range(32): rec[i] ^= key[i % 16]print(rec) SYC{Then_you_are_1mpressivse} MiscBite off picture解压缩包发现被加密了，根据提示在010中发现编码 一个翻过来的base64，反转一下解密就行werwerr，解压得到一张图片，用随波 逐流分析发现被修改了宽高，随波逐流直接自动更正，或者去学一下文件结构010改宽高 hiddenflag1其实是隐藏文字，把隐藏文字可见打开就可以打开文件时不是正常打开，所以把后缀改成zip再寻找剩余flag，都在doc文件夹 里，其中flag3需要修复文件头，jpg文件缺失文件头FF D8，补