from Crypto.Util.number import *from gmpy2 import * = 65537p = 7221289171488727827673517139597844534869368289455419695964957239047692699919030405800116133805855968123601433247022090070114331842771417566928809956044421q = 7221289171488727827673517139597844534869368289455419695964957239047692699919030405800116133805855968123601433247022090070114331842771417566928809956045093phi = (p-1)*(q-1)d = inverse(e, phi)m = int(powmod(c, d, n)) flag = long_to_bytes(m)print(flag)# flag&#123;9cd4b35a-affc-422a-9862-58e1cc3ff8d2&#125;

