from Crypto.Cipher import AESfrom Crypto.Util.Padding import unpadimport base64cipher=bytearray([0xc2, 0x6c, 0x73, 0xf4, 0x3a, 0x45, 0xe, 0xba, 0x47, 0x81, 0x2a, 0x26, 0xf6, 0x79, 0x60, 0x78, 0xb3, 0x64, 0x6d, 0xdc, 0xc9, 0x4, 0x32, 0x3b, 0x9f, 0x32, 0x95, 0x60, 0xee, 0x82, 0x97, 0xe7, 0xca, 0x3d, 0xaa, 0x95, 0x76, 0xc5, 0x9b, 0x1d, 0x89, 0xdb, 0x98, 0x5d])key=b&quot;meow&quot;aes_key=b&quot;IamEzEncryptGame&quot;def RC4(data: bytes, key: bytes) -&gt; bytearray:    S = list(range(256))    j = 0    out = bytearray()    # KSA    for i in range(256):        j = (j + S[i] + key[i % len(key)]) % 256        S[i], S[j] = S[j], S[i]    # PRGA    i = j = 0    for char in data:        i = (i + 1) % 256        j = (j + S[i]) % 256        S[i], S[j] = S[j], S[i]        K = S[(S[i] + S[j]) % 256]        out.append(char ^ K)    return outnative_en=RC4(cipher, key)for i in range(len(native_en)):    native_en[i]^=key[i%len(key)]ret_java_cip=base64.b64decode(native_en)cipher_aes = AES.new(aes_key, AES.MODE_ECB)flag = unpad(cipher_aes.decrypt(ret_java_cip), AES.block_size)print(flag.decode())# flag&#123;0hh_U_kn0w_7h15_5ki11&#125;


